-- Chien -> humain, Anniversaire, Volume 5

insert into public.message_templates (user_id,title,content,tone,is_system,is_manual_only,occasion,animal_type,animal_direction) values

(null,'Pour ton anniversaire j''ai dormi sur l''invitation que tu avais écrite.',$$Pour ton anniversaire j''ai dormi sur l''invitation que tu avais écrite.
Celle avec les noms. Les horaires. L''adresse. Posée sur le buffet depuis trois jours. Je m''y suis installé le premier soir. Puis le deuxième. Puis le troisième. Elle portait ton écriture à la main. Et quelque chose de l''anticipation de cette soirée. Dormir dessus c''était dormir sur le projet de ce soir avant qu''il devienne réel. Joyeux anniversaire, mon humain préféré.
Avec occupation de l''invitation et connexion à l''anticipation de la soirée, — {prenom}, ton animal présent dans tes projets avant même qu''ils se réalisent 📋$$,'humorous',true,false,'birthday','chien','from'),

(null,'Joyeux anniversaire. Je comprends pas pourquoi les gens rient aux blagues qu''ils connaissent déjà.',$$Joyeux anniversaire. Je comprends pas pourquoi les gens rient aux blagues qu''ils connaissent déjà.
Il y en a eu une ce soir. Quelqu''un a commencé à la raconter et deux personnes souriaient déjà avant la chute parce qu''ils savaient. Et pourtant quand c''est arrivé tout le monde a ri. Peut-être que c''est pas la surprise qui fait rire. Peut-être que c''est être ensemble à ce moment précis. Joyeux anniversaire, mon humain préféré.
Avec théorie sur le rire de reconnaissance et progrès dans la compréhension humaine, — {prenom}, ton animal philosophe des mécanismes du rire 😄$$,'humorous',true,false,'birthday','chien','from'),

(null,'Pour ton anniversaire j''ai observé ta façon d''ajuster les décorations sur la table.',$$Pour ton anniversaire j''ai observé ta façon d''ajuster les décorations sur la table.
Le vase un peu à gauche. La nappe recentrée. Les bougies déplacées de quelques centimètres. Ces micro-ajustements entre deux passages. Ces gestes automatiques qui disent que tu veux que ce soit bien. Que les choses soient à leur place. Joyeux anniversaire, mon humain préféré.
Avec observation de tes micro-ajustements décoratifs et leur signification de soin, — {prenom}, ton animal attentif à tes soins invisibles 🕯️$$,'humorous',true,false,'birthday','chien','from'),

(null,'Joyeux anniversaire. J''ai mémorisé l''ordre d''arrivée et l''odeur de chaque invité.',$$Joyeux anniversaire. J''ai mémorisé l''ordre d''arrivée et l''odeur de chaque invité.
Le premier à 19h47 avec cette odeur de laine mouillée. Le deuxième à 19h53 avec son parfum habituel. Le troisième à 20h02 avec quelque chose que je n''avais jamais senti et qui était intéressant. Chaque arrivée une entrée dans ma base de données. Joyeux anniversaire, mon humain préféré, entouré de gens que je connais maintenant par cœur.
Avec base de données olfactive des invités enrichie et profils tous constitués, — {prenom}, ton animal archiviste des arrivées 👃$$,'humorous',true,false,'birthday','chien','from'),

(null,'Joyeux anniversaire. J''ai observé ta façon de te déplacer dans la cuisine sous pression.',$$Joyeux anniversaire. J''ai observé ta façon de te déplacer dans la cuisine sous pression.
Efficace. Précis. Tu sais où tout est. Tu ne cherches pas. Tu pivotes. Tu ouvres. Tu prends. Tu fermes. Tu repivotes. Pas de geste inutile. Cette économie de mouvement sous pression. Moi dans la cuisine je suis pareil. Je sais exactement où est la gamelle. On se ressemble. Joyeux anniversaire, mon humain préféré.
Avec reconnaissance de notre efficacité commune en cuisine et solidarité de méthode, — {prenom}, ton animal partenaire en déplacements précis 🏃$$,'humorous',true,false,'birthday','chien','from'),

(null,'Pour ton anniversaire j''ai passé du temps à étudier chaque cadeau avant que tu les ouvres.',$$Pour ton anniversaire j''ai passé du temps à étudier chaque cadeau avant que tu les ouvres.
Reniflage systématique. Évaluation structurelle. Certains sentaient le neuf. Un sentait le bois. Un autre sentait quelque chose que je n''ai pas identifié et ça me tracasse encore. J''avais toutes les données. Toi tu as eu la surprise. On a chacun notre façon de vivre les cadeaux. Joyeux anniversaire, mon humain préféré.
Avec audit olfactif complet des cadeaux et mystère d''un emballage non résolu, — {prenom}, ton animal enquêteur des présents 🔍$$,'humorous',true,false,'birthday','chien','from'),

(null,'Joyeux anniversaire. Je comprends pas pourquoi les gens chantent plus fort sur certains mots.',$$Joyeux anniversaire. Je comprends pas pourquoi les gens chantent plus fort sur certains mots.
La chanson d''anniversaire. Ces mots qui reçoivent plus d''air. Plus de voix. Comme si certains mots méritaient plus de son que d''autres. Peut-être que c''est leur façon de dire que ces mots comptent plus. Dans ce cas ton prénom ce soir a reçu beaucoup de son. C''est mérité. Joyeux anniversaire, mon humain préféré.
Avec théorie de l''emphase syllabique et conclusion que ton prénom méritait cet air supplémentaire, — {prenom}, ton animal linguiste des chansons 🎵$$,'humorous',true,false,'birthday','chien','from'),

(null,'Pour ton anniversaire j''ai observé ta façon de présenter le gâteau.',$$Pour ton anniversaire j''ai observé ta façon de présenter le gâteau.
Tu l''as apporté toi-même depuis la cuisine. Avec les bougies allumées. Lentement pour ne pas les éteindre en marchant. Les yeux sur les flammes. Cette concentration. Cette façon de porter quelque chose de précieux. Et la pièce qui s''est arrêtée. Et tout le monde qui regardait. Et toi au centre de tout ça. Joyeux anniversaire, mon humain préféré.
Avec observation de ta façon de porter la lumière vers les gens et sa signification, — {prenom}, ton animal témoin de tes gestes solennels 🎂$$,'humorous',true,false,'birthday','chien','from'),

(null,'Joyeux anniversaire. J''ai compté combien de fois tu as vérifié l''heure.',$$Joyeux anniversaire. J''ai compté combien de fois tu as vérifié l''heure.
Neuf fois. Pas parce que tu t''ennuyais. Je le sais parce que tu souriais souvent après. C''était pour vérifier que tout avançait bien. Que le repas était prêt au bon moment. Que les gens n''allaient pas partir trop tôt. Joyeux anniversaire, mon humain préféré, dont la précision temporelle fait partie du soin.
Avec neuf consultations horaires comptées et leur nature de soin bien établie, — {prenom}, ton animal chronomètre de tes soirées ⌚$$,'humorous',true,false,'birthday','chien','from'),

(null,'Joyeux anniversaire. J''ai observé le moment où tes épaules sont enfin descendues.',$$Joyeux anniversaire. J''ai observé le moment où tes épaules sont enfin descendues.
20h47. Tu étais en conversation avec quelqu''un que tu aimes vraiment. Et tes épaules ont quitté ce niveau légèrement haut où elles étaient depuis le début de la soirée. Elles sont descendues d''un cran. Naturellement. Ce relâchement. Cette confiance dans le moment. Joyeux anniversaire, mon humain préféré.
Avec détection du relâchement des épaules à 20h47 et soulagement partagé depuis mon coin, — {prenom}, ton animal baromètre de ta tension 😌$$,'humorous',true,false,'birthday','chien','from'),

(null,'Pour ton anniversaire j''ai suivi l''évolution de la chaleur de l''appartement.',$$Pour ton anniversaire j''ai suivi l''évolution de la chaleur de l''appartement.
Au début la température normale. Puis avec les premières arrivées ça monte. Le repas encore plus. À 21h c''était le pic. Puis les départs progressifs et le retour vers la normale. L''appartement respire selon le nombre de corps qu''il contient. Joyeux anniversaire, mon humain préféré, dont l''appartement sait accueillir la chaleur.
Avec monitoring thermique de la soirée et bilan positif rendu, — {prenom}, ton animal thermomètre de l''ambiance 🌡️$$,'humorous',true,false,'birthday','chien','from'),

(null,'Joyeux anniversaire. Je comprends pas pourquoi les gens arrivent avec des choses à mettre au frigo.',$$Joyeux anniversaire. Je comprends pas pourquoi les gens arrivent avec des choses à mettre au frigo.
Plusieurs ce soir avaient quelque chose qui devait rester froid. Direction la cuisine. Direction le frigo. Ce ballet vers le frigo comme première interaction avec ton appartement. Le frigo comme portail d''entrée dans ta fête. Joyeux anniversaire, mon humain préféré.
Avec théorie du frigo comme portail festif et observations empiriques solides, — {prenom}, ton animal sociologue de l''entrée en cuisine 🥗$$,'humorous',true,false,'birthday','chien','from'),

(null,'Pour ton anniversaire j''ai observé ta façon de toucher l''épaule de quelqu''un quand tu parles.',$$Pour ton anniversaire j''ai observé ta façon de toucher l''épaule de quelqu''un quand tu parles.
Tu fais ça avec les gens que tu aimes vraiment. Une main sur l''épaule quand tu veux que le mot arrive bien. Que l''autre sache que tu es vraiment là. J''ai compté les épaules touchées ce soir. Quatre personnes. Quatre personnes qui comptent vraiment. Joyeux anniversaire, mon humain préféré.
Avec registre des épaules touchées et cartographie affective déduite, — {prenom}, ton animal expert en gestes d''attachement 🤝$$,'humorous',true,false,'birthday','chien','from'),

(null,'Joyeux anniversaire. J''ai observé qui mangeait le plus lentement ce soir.',$$Joyeux anniversaire. J''ai observé qui mangeait le plus lentement ce soir.
C''était celle qui parle le plus. Logiquement. Elle mangeait entre deux phrases. Moi je comprends pas cette économie de l''attention. Manger c''est une activité qui mérite une concentration totale. Mais son assiette était finie à la fin. Et elle semblait heureuse. Je ne juge pas. Joyeux anniversaire, mon humain préféré.
Avec étude des rythmes alimentaires et incompréhension bienveillante du repas conversationnel, — {prenom}, ton animal pour qui manger est une activité sacrée et unique 🍽️$$,'humorous',true,false,'birthday','chien','from'),

(null,'Pour ton anniversaire j''ai observé ta façon de t''assurer que tout le monde a à boire.',$$Pour ton anniversaire j''ai observé ta façon de t''assurer que tout le monde a à boire.
Tu fais le tour des yeux régulièrement. Tu repères les verres vides. Tu proposes sans insister. Tu vas chercher sans qu''on te le demande. Cette attention distribuée en permanence. Moi j''ai ma gamelle et c''est réglé. Toi tu gères les gamelles de tout le monde toute la soirée. Joyeux anniversaire, mon humain préféré.
Avec admiration pour ta gestion des gamelles collectives et reconnaissance de ton énergie, — {prenom}, ton animal qui gère une seule gamelle et c''est déjà bien 🥃$$,'humorous',true,false,'birthday','chien','from'),

(null,'Joyeux anniversaire. J''ai identifié le moment exact où la fête a vraiment commencé.',$$Joyeux anniversaire. J''ai identifié le moment exact où la fête a vraiment commencé.
Pas quand le premier invité est arrivé. À 20h18 quand quelqu''un a ri vraiment fort et que toutes les autres conversations se sont arrêtées une seconde puis reprises plus fort. Ce rire synchronisateur. Ce moment où les gens arrêtent d''être des individus et deviennent un groupe. Là. C''est là. Joyeux anniversaire, mon humain préféré.
Avec identification précise du moment fondateur à 20h18 et théorie du rire comme déclencheur de groupe, — {prenom}, ton animal détecteur des moments où tout commence 🎉$$,'humorous',true,false,'birthday','chien','from'),

(null,'Joyeux anniversaire. Je comprends pas pourquoi les gens repartent avec moins qu''ils sont venus.',$$Joyeux anniversaire. Je comprends pas pourquoi les gens repartent avec moins qu''ils sont venus.
Ils arrivent avec des bouteilles. Des gâteaux. Des fleurs. Des cadeaux. Et ils repartent avec juste leur manteau. Tout ce qu''ils ont apporté reste ici. Dans ton appartement. Comme si venir chez toi c''était laisser quelque chose. Joyeux anniversaire, mon humain préféré.
Avec réflexion sur l''économie des objets festifs et conclusion sur la valeur de ton espace, — {prenom}, ton animal philosophe des échanges 🎀$$,'humorous',true,false,'birthday','chien','from'),

(null,'Pour ton anniversaire j''ai observé ta façon de froncer les sourcils quand tu cherches quelque chose.',$$Pour ton anniversaire j''ai observé ta façon de froncer les sourcils quand tu cherches quelque chose.
Les sourcils légèrement rapprochés. Les yeux qui balaient la pièce systématiquement. De gauche à droite. Puis l''inverse. Ce soir tu as cherché le tire-bouchon. Puis les allumettes. Ce schéma de recherche. Cette méthode. Très toi. Joyeux anniversaire, mon humain préféré.
Avec étude de ton pattern de recherche visuelle et sa cohérence parfaite, — {prenom}, ton animal lecteur de tes expressions de concentration 🔍$$,'humorous',true,false,'birthday','chien','from'),

(null,'Pour ton anniversaire j''ai observé comment tu changes de position sur le canapé selon l''interlocuteur.',$$Pour ton anniversaire j''ai observé comment tu changes de position sur le canapé selon l''interlocuteur.
Avec certains tu te tournes entièrement. Corps complet dans leur direction. Avec d''autres tu restes de face mais la tête pivote. Avec d''autres encore tu t''appuies en arrière et tu les laisses venir à toi. Chaque position dit quelque chose sur la relation. Ce soir j''ai lu toutes tes positions. Joyeux anniversaire, mon humain préféré.
Avec décodage de tes positions de canapé et leur signification relationnelle établie, — {prenom}, ton animal herméneute du corps 🛋️$$,'touching',true,false,'birthday','chien','from')

on conflict do nothing;
